#!/usr/bin/env python3
"""Write a FLUX token sidecar (clip_ids + t5_ids) for a prompt, using the LOCAL
HF tokenizer snapshots already present under the model scratch dir. Tokenizer-
only (no torch / no network). Mirrors the dali sidecar schema the --real path
consumes (clip_max_length=77, t5_max_length=512, EOS/pad-filled).
"""
from __future__ import annotations
import argparse
import json
import os
from pathlib import Path

import sentencepiece as spm
from tokenizers import Tokenizer


def pad_to(ids: list[int], length: int, pad_id: int) -> list[int]:
    ids = ids[:length]
    return ids + [pad_id] * (length - len(ids))


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--prompt", required=True)
    ap.add_argument("--out", required=True)
    ap.add_argument("--scratch", default=str(Path(os.environ.get(
        "MODEL_SCRATCH",
        Path(__file__).resolve().parents[4] / ".a0/model-scratch/flux-1-schnell",
    ))))
    ap.add_argument("--clip-max", type=int, default=77)
    ap.add_argument("--t5-max", type=int, default=512)
    args = ap.parse_args()

    hub = Path(args.scratch) / "hf" / "hub"
    clip_snap = next((hub / "models--openai--clip-vit-large-patch14" / "snapshots").iterdir())
    t5_snap = next((hub / "models--google--t5-v1_1-xxl" / "snapshots").iterdir())

    # CLIP: fast tokenizer.json present in the snapshot.
    clip = Tokenizer.from_file(str(clip_snap / "tokenizer.json"))
    clip_enc = clip.encode(args.prompt)  # includes BOS 49406 / EOS 49407
    clip_ids = clip_enc.ids
    clip_eos = 49407  # CLIP <|endoftext|> = pad = eos
    clip_bos = 49406

    # T5-XXL v1_1: spiece.model directly (no fast tokenizer); EOS=1, pad=0, no BOS.
    sp = spm.SentencePieceProcessor(model_file=str(t5_snap / "spiece.model"))
    t5_eos = sp.eos_id() if sp.eos_id() >= 0 else 1
    t5_pad = sp.pad_id() if sp.pad_id() >= 0 else 0
    t5_ids = list(sp.encode(args.prompt)) + [t5_eos]

    sidecar = {
        "model_id": "black-forest-labs/FLUX.1-schnell",
        "tokenizer_sources": {
            "clip": {"model_id": "openai/clip-vit-large-patch14", "subfolder": None},
            "t5": {"model_id": "google/t5-v1_1-xxl", "subfolder": None},
        },
        "prompt": args.prompt,
        "negative_prompt": "",
        "clip_ids": pad_to(clip_ids, args.clip_max, clip_eos),
        "t5_ids": pad_to(t5_ids, args.t5_max, t5_pad),
        "negative_clip_ids": pad_to([clip_bos, clip_eos], args.clip_max, clip_eos),
        "negative_t5_ids": pad_to([t5_eos], args.t5_max, t5_pad),
        "clip_max_length": args.clip_max,
        "t5_max_length": args.t5_max,
    }
    Path(args.out).parent.mkdir(parents=True, exist_ok=True)
    Path(args.out).write_text(json.dumps(sidecar, indent=2))
    print(f"wrote {args.out}")
    print(f"  clip_ids[:10] = {sidecar['clip_ids'][:10]}")
    print(f"  t5_ids[:10]   = {sidecar['t5_ids'][:10]}")


if __name__ == "__main__":
    main()
